if (typeof Chart === 'undefined') {
    window.Chart = function(ctx, config) {
        console.log('Chart.js not loaded. Please install Chart.js library.');
        
        // Mock implementation for development
        this.config = config;
        this.ctx = ctx;
        
        this.destroy = function() {
            console.log('Chart destroyed');
        };
        
        this.resize = function() {
            console.log('Chart resized');
        };
        
        this.update = function() {
            console.log('Chart updated');
        };
        
        // Draw a simple placeholder
        if (ctx && ctx.canvas) {
            const canvas = ctx.canvas;
            ctx.fillStyle = '#666';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.font = '14px Arial';
            ctx.fillText('Chart.js not loaded', canvas.width / 2, canvas.height / 2);
            ctx.fillText('Please install Chart.js library', canvas.width / 2, canvas.height / 2 + 20);
        }
        
        return this;
    };
    
    // Add static methods
    window.Chart.register = function() {
        console.log('Chart.register called (mock)');
    };
    
    window.Chart.defaults = {
        responsive: true,
        maintainAspectRatio: false
    };
}